SELECT id, space_id, title, description, start_date, end_date, location, price, color, status, created_by, created_at, updated_at
FROM events
WHERE id = #{id}


SELECT id, space_id, title, description, start_date, end_date, location, price, color, status, created_by, created_at, updated_at
FROM events
WHERE space_id = #{spaceId}
  AND TO_CHAR(start_date, 'YYYY-MM') = #{month}
ORDER BY start_date ASC
